# Resource: data by URI; a template with a parameter
@mcp.resource("report://{month}")
def monthly_report(month: str) -> str:
    """Monthly sales report in Markdown format."""
    return load_report(month)

# Prompt: a template the user invokes themselves
@mcp.prompt()
def weekly_report() -> str:
    """Assemble the weekly report by the team template."""
    return (
        "Assemble the weekly report: take the data with the "
        "get_sales tool, group by region, and format it as a table "
        "with columns: region, sales, change vs. last week."
    )

@mcp.tool()
def get_sales(month: str) -> str:
    """Sales for a month. month — in YYYY-MM format, for example 2026-07."""
    if not re.fullmatch(r"\d{4}-\d{2}", month):
        return f"Error: month must be in YYYY-MM format (got: {month}). Rephrase the request."
    try:
        return fetch_sales(month)
    except ConnectionError:
        return "Error: the database is unavailable. Tell the user and offer to retry later."
